int main() {
    // Create and print Person
    return 0;
}

exercises.solutionCode:
#include <stdio.h>
#include <string.h>
struct Person {
    char name[30];
    int age;
};
int main() {
    struct Person p1;
    strcpy(p1.name, "Sanjith");
    p1.age = 25;
    printf("%s\n", p1.name);
    printf("%d\n", p1.age);
    return 0;
}

